@InjectRepository(BookmarkEntity)
private readonly bookmarkRepository: Repository<BookmarkEntity>

async bookmark(userId: number, slug: string): Promise<ArticleRO> {
  const article = await this.articleRepository.findOne({slug});
  const bookmark = await this.bookmarkRepository.findOne({userId, articleId: article.id});

  if (!bookmark) {
    const newBookmark = new BookmarkEntity();
    newBookmark.userId = userId;
    newBookmark.articleId = article.id;
    await this.bookmarkRepository.save(newBookmark);
  }

  return {article};
}

async unbookmark(userId: number, slug: string): Promise<ArticleRO> {
  const article = await this.articleRepository.findOne({slug});
  await this.bookmarkRepository.delete({userId, articleId: article.id});
  return {article};
}

async getBookmarks(userId: number, query): Promise<ArticlesRO> {
  const qb = this.articleRepository.createQueryBuilder('article')
    .innerJoin('bookmark', 'bookmark', 'bookmark.articleId = article.id')
    .where('bookmark.userId = :userId', {userId})
    .orderBy('bookmark.created', 'DESC');

  const articlesCount = await qb.getCount();

  if ('limit' in query) qb.limit(query.limit);
  if ('offset' in query) qb.offset(query.offset);

  const articles = await qb.getMany();
  return {articles, articlesCount};
}
```

